// ─── Prepare Input: Simplify payload for full LLM processing ───
const body = $json.body || $json;
const baseResume = body.baseResume || '';
const jobDescription = body.jobDescription || '';
const recipientEmail = body.recipientEmail || 'rvnegi786@gmail.com';
const companyName = body.companyName || 'the company';

return {
  jobDescription,
  baseResume,
  recipientEmail,
  companyName
};

// ─── Prepare Doc Content: Parse LLM JSON ───
const llmRaw = $("Generate Tailored Resume").item.json.text || '';
let resumeData = {};

try {
  // Clean markdown blocks if present
  const cleaned = llmRaw.replace(/```json/g, '').replace(/```/g, '').trim();
  resumeData = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse LLM response as JSON: ' + e.message + '\nRaw: ' + llmRaw);
}

const meta = $("Prepare Input").item.json;
const dateStr = new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });

return {
  resumeData,
  recipientEmail: meta.recipientEmail,
  companyName: meta.companyName,
  emailBody: `<p>Hi,</p><p>Your tailored resume for <strong>${meta.companyName}</strong> is attached.</p><p>Best of luck!</p>`,
  subject: `📄 Resume for ${meta.companyName} — ${dateStr}`
};

// ─── PDF Generator v4 — Structured, Professional, Optimized ───
const PDFDocument = require('pdfkit');
const meta = $("Prepare Doc Content").item.json;
const data = meta.resumeData || {};

const pdfBuffer = await new Promise((resolve, reject) => {
  const doc = new PDFDocument({
    size: 'A4', 
    margins: { top: 35, bottom: 30, left: 40, right: 40 },
    autoFirstPage: true,
    bufferPages: true
  });
  const chunks = [];
  doc.on('data', c => chunks.push(c));
  doc.on('end', () => resolve(Buffer.concat(chunks)));
  doc.on('error', reject);

  const PW = doc.page.width;
  const ML = 40, MR = 40;
  const L = ML, R = PW - MR, CW = R - L;
  const BLACK = '#000000', DARK_GRAY = '#333333', BLUE = '#0047AB', RULE = '#BBBBBB';

  const stripMd = (s) => String(s || '').replace(/\*\*(.*?)\*\*/g, '$1').replace(/\*(.*?)\*/g, '$1').trim();

  // ── Helper: Draw Section Header ──
  const drawSectionHeader = (title) => {
    if (doc.y > 740) doc.addPage();
    doc.moveDown(0.8);
    doc.font('Helvetica-Bold').fontSize(11).fillColor(BLACK)
       .text(stripMd(title).toUpperCase(), L, doc.y, { width: CW });
    const ry = doc.y + 1.5;
    doc.moveTo(L, ry).lineTo(R, ry).lineWidth(0.6).strokeColor(RULE).stroke();
    doc.moveDown(0.4);
  };

  // ── Helper: Draw Bullet ──
  const drawBullet = (text, xOffset = 15) => {
    if (!text) return;
    doc.font('Helvetica').fontSize(9.5).fillColor(DARK_GRAY)
       .text('• ', L + 5, doc.y, { continued: true })
       .text(stripMd(text), { width: CW - xOffset, lineGap: 2.2, align: 'justify' });
    doc.moveDown(0.12);
  };

  // ── Helper: Draw Row (Left/Right) ──
  const drawRow = (left, right, isBold = false) => {
    const sy = doc.y;
    const lWidth = CW - 110;
    const lFont = isBold ? 'Helvetica-Bold' : 'Helvetica';
    const cleanLeft = stripMd(left);
    const cleanRight = stripMd(right);

    // Draw right part first (usually date)
    if (cleanRight) {
      doc.font('Helvetica-Oblique').fontSize(9).fillColor(DARK_GRAY)
         .text(cleanRight, L, sy, { width: CW, align: 'right' });
    }

    // Draw left part (title/company) which might wrap
    doc.font(lFont).fontSize(10).fillColor(BLACK)
       .text(cleanLeft, L, sy, { width: lWidth });

    // Calculate accurate height of left block and move cursor below it
    const h = doc.heightOfString(cleanLeft, { width: lWidth });
    doc.y = sy + h;
    doc.moveDown(0.2);
  };

  // ── 1. HEADER ──
  const h = data.header || {};
  doc.font('Helvetica-Bold').fontSize(18).fillColor(BLACK).text(stripMd(h.name) || '', { align: 'center' });
  doc.moveDown(0.1);
  doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY).text(stripMd(h.contact) || '', { align: 'center' });

  if (h.links && h.links.length) {
    doc.moveDown(0.1);
    let currentY = doc.y;
    let currentX = L;
    const totalLinksWidth = h.links.reduce((acc, curve) => acc + doc.widthOfString(curve.label + ' | '), 0);
    let startX = (PW - totalLinksWidth) / 2;
    h.links.forEach((link, idx) => {
      doc.font('Helvetica').fontSize(9).fillColor(BLUE)
         .text(stripMd(link.label), startX, currentY, { link: link.url, continued: idx < h.links.length - 1 });
      if (idx < h.links.length - 1) {
        doc.fillColor(DARK_GRAY).text(' | ', { continued: true });
      }
      startX += doc.widthOfString(link.label + ' | ');
    });
    doc.text('', { continued: false }).moveDown(0.3);
  }

  // ── 2. SUMMARY ──
  if (data.summary) {
    drawSectionHeader('Professional Summary');
    doc.font('Helvetica').fontSize(9.5).fillColor(DARK_GRAY).text(stripMd(data.summary), { width: CW, align: 'justify', lineGap: 2.2 });
  }

  // ── 3. SKILLS ──
  if (data.skills && data.skills.length) {
    drawSectionHeader('Technical Skills');
    data.skills.forEach(s => {
      doc.font('Helvetica-Bold').fontSize(9.5).fillColor(BLACK).text(stripMd(s.category) + ': ', L, doc.y, { continued: true })
         .font('Helvetica').text(s.items.map(stripMd).join(', '), { width: CW, lineGap: 1.8 });
      doc.moveDown(0.1);
    });
  }

  // ── 4. EXPERIENCE ──
  if (data.experience && data.experience.length) {
    drawSectionHeader('Professional Experience');
    data.experience.forEach(exp => {
      drawRow(`${stripMd(exp.title)} | ${stripMd(exp.company)}`, exp.date, true);
      if (exp.bullets) exp.bullets.forEach(b => drawBullet(b));
      doc.moveDown(0.25);
    });
  }

  // ── 5. PROJECTS ──
  if (data.projects && data.projects.length) {
    drawSectionHeader('Projects');
    data.projects.forEach(p => {
      const sy = doc.y;
      const cleanTitle = stripMd(p.title);
      doc.font('Helvetica-Bold').fontSize(9.5).fillColor(BLACK).text(cleanTitle, L, sy, { continued: !!p.link });
      if (p.link) {
        const displayUrl = p.link.replace(/^https?:\/\//, '');
        doc.font('Helvetica').fontSize(8.5).fillColor(BLUE).text(` (${displayUrl})`, { link: p.link });
      } else {
        doc.text('');
      }
      if (p.bullets) p.bullets.forEach(b => drawBullet(b));
      doc.moveDown(0.1);
    });
  }

  // ── 6. AWARDS ──
  if (data.awards && data.awards.length) {
    drawSectionHeader('Awards & Recognition');
    data.awards.forEach(a => {
      const sy = doc.y;
      const cleanTitle = stripMd(a.title);
      doc.font('Helvetica-Bold').fontSize(9).fillColor(BLACK).text(cleanTitle, L, sy, { continued: !!(a.link || a.description) });
      if (a.link) doc.font('Helvetica').fontSize(8).fillColor(BLUE).text(` (Link)`, { link: a.link, continued: !!a.description });
      if (a.description) doc.font('Helvetica').fontSize(9).fillColor(DARK_GRAY).text(` — ${stripMd(a.description)}`, { continued: false });
      else doc.text('');
      doc.moveDown(0.08);
    });
  }

  // ── 7. EDUCATION ──
  if (data.education && data.education.length) {
    drawSectionHeader('Education');
    data.education.forEach(edu => {
      drawRow(`${stripMd(edu.degree)} | ${stripMd(edu.school)}`, edu.date, true);
      if (edu.details) {
        doc.font('Helvetica').fontSize(8.5).fillColor(DARK_GRAY).text(stripMd(edu.details), L + 10, doc.y, { width: CW - 10 });
      }
      doc.moveDown(0.1);
    });
  }

  doc.end();
});

return {
  json: {
    recipientEmail: meta.recipientEmail,
    subject: meta.subject,
    emailBody: meta.emailBody
  },
  binary: {
    data: {
      data: pdfBuffer.toString('base64'),
      mimeType: 'application/pdf',
      fileName: `Resume_${meta.companyName.replace(/\s+/g, '_')}.pdf`
    }
  }
};
